class Animal {
  constructor(public name: string) {}

  move(distanceMeters: number): void {
    console.log(`${this.name} moved ${distanceMeters}m.`);
  }

  makeSound(): string {
    return '...';
  }
}

class Dog extends Animal {
  constructor(name: string, public breed: string) {
    super(name); // must call super() before accessing this
  }

  override makeSound(): string {
    return 'Woof!';
  }

  fetch(): void {
    console.log(`${this.name} fetches the ball.`);
  }
}

const rex = new Dog('Rex', 'Labrador');
rex.move(10);          // Animal.move — inherited
rex.fetch();           // Dog.fetch — own method
console.log(rex.makeSound()); // Dog.makeSound — overridden
console.log(rex instanceof Dog);    // true
console.log(rex instanceof Animal); // true — instanceof is true for all ancestors

class Vehicle {
  protected speed = 0;

  constructor(public readonly make: string, public readonly model: string) {}

  accelerate(amount: number): void {
    this.speed += amount;
  }

  describe(): string {
    return `${this.make} ${this.model} at ${this.speed}km/h`;
  }
}

class ElectricCar extends Vehicle {
  private batteryLevel = 100;

  constructor(make: string, model: string, public readonly range: number) {
    super(make, model); // delegates to Vehicle constructor
  }

  override accelerate(amount: number): void {
    super.accelerate(amount); // call base method first
    this.batteryLevel -= amount * 0.1; // additional subclass logic
    console.log(`Battery: ${this.batteryLevel.toFixed(0)}%`);
  }

  override describe(): string {
    return `${super.describe()} (electric, range: ${this.range}km)`;
    // extend the base description instead of replacing it
  }
}

const car = new ElectricCar('Tesla', 'Model 3', 560);
car.accelerate(50);         // Battery: 95%
console.log(car.describe()); // Tesla Model 3 at 50km/h (electric, range: 560km)

class Base {
  greet(): string { return 'Hello from Base'; }
}

class Child extends Base {
  override greet(): string { return 'Hello from Child'; } // OK — greet exists in Base

  // override grrete(): string { return ''; } // Error: 'grrete' does not exist in 'Base'
  // Catches typos silently if you forget the override keyword
}

// noImplicitOverride compiler option:
// When enabled, TypeScript requires the override keyword on any method
// that overrides a base class method. Without it, you get a compile error.
// This prevents silent accidental overrides when a base class adds a method
// with the same name as an existing subclass method.

abstract class Shape {
  // Concrete property — shared by all shapes
  constructor(public readonly color: string) {}

  // Abstract method — subclasses MUST implement this
  abstract area(): number;
  abstract perimeter(): number;

  // Concrete method — shared implementation
  describe(): string {
    return `${this.color} shape with area ${this.area().toFixed(2)}`;
  }
}

class Circle extends Shape {
  constructor(color: string, public readonly radius: number) {
    super(color);
  }

  override area(): number      { return Math.PI * this.radius ** 2; }
  override perimeter(): number { return 2 * Math.PI * this.radius; }
}

class Rectangle extends Shape {
  constructor(color: string, public readonly width: number, public readonly height: number) {
    super(color);
  }

  override area(): number      { return this.width * this.height; }
  override perimeter(): number { return 2 * (this.width + this.height); }
}

// const s = new Shape('red'); // Error: Cannot create an instance of an abstract class.
const c = new Circle('blue', 5);
const r = new Rectangle('red', 4, 6);

console.log(c.describe()); // blue shape with area 78.54
console.log(r.describe()); // red shape with area 24.00

// Works as a type — Shape is a valid parameter type
function printArea(shape: Shape): void {
  console.log(shape.area());
}
printArea(c); // 78.54
printArea(r); // 24

class Person {
  constructor(
    public readonly name: string,
    protected age: number, // accessible in subclasses
  ) {}

  protected getAge(): number { return this.age; }
}

class Employee extends Person {
  constructor(name: string, age: number, public readonly department: string) {
    super(name, age);
  }

  getInfo(): string {
    // protected age and getAge() are accessible here
    return `${this.name}, age ${this.getAge()}, works in ${this.department}`;
  }
}

const emp = new Employee('Alice', 30, 'Engineering');
console.log(emp.getInfo()); // 'Alice, age 30, works in Engineering'
