interface Serializable {
  serialize(): string;
}

interface Validatable {
  isValid(): boolean;
}

// A class can implement multiple interfaces
class UserModel implements Serializable, Validatable {
  constructor(
    public readonly id: number,
    public name: string,
    public email: string,
  ) {}

  serialize(): string {
    return JSON.stringify({ id: this.id, name: this.name, email: this.email });
  }

  isValid(): boolean {
    return this.name.length > 0 && this.email.includes('@');
  }
}

const u = new UserModel(1, 'Alice', 'alice@example.com');
console.log(u.isValid());   // true
console.log(u.serialize()); // {"id":1,"name":"Alice","email":"alice@example.com"}

// An abstract class can implement an interface too
abstract class AbstractModel implements Serializable {
  abstract serialize(): string; // implementation delegated to concrete subclasses
}

import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

interface HasId { id: number }

// Abstract base — shared HTTP logic, no registration in DI
abstract class CrudService<T extends HasId> {
  protected readonly http = inject(HttpClient);
  protected abstract readonly url: string;

  getAll(): Observable<T[]>     { return this.http.get<T[]>(this.url); }
  getById(id: number): Observable<T> { return this.http.get<T>(`${this.url}/${id}`); }
  create(body: Omit<T, 'id'>): Observable<T> { return this.http.post<T>(this.url, body); }
  update(id: number, body: Partial<T>): Observable<T> {
    return this.http.patch<T>(`${this.url}/${id}`, body);
  }
  delete(id: number): Observable<void> { return this.http.delete<void>(`${this.url}/${id}`); }
}

interface User    { id: number; name: string; email: string }
interface Product { id: number; name: string; price: number }

// Concrete subclasses — register in DI, provide concrete url
@Injectable({ providedIn: 'root' })
class UserService extends CrudService<User> {
  protected override readonly url = '/api/users';
}

@Injectable({ providedIn: 'root' })
class ProductService extends CrudService<Product> {
  protected override readonly url = '/api/products';
}

class Event {
  constructor(
    public readonly id: string,
    public readonly createdAt: Date,
  ) {}

  format(): string { return `[${this.id}] at ${this.createdAt.toISOString()}`; }
}

class UserEvent extends Event {
  constructor(
    id: string,
    createdAt: Date,
    public readonly userId: number,
    public readonly action: string,
  ) {
    super(id, createdAt); // base params first, then sub-specific params
  }

  override format(): string {
    return `${super.format()} — user ${this.userId}: ${this.action}`;
  }
}

const e = new UserEvent('e1', new Date(), 42, 'login');
console.log(e.format());
// [e1] at 2024-01-01T00:00:00.000Z — user 42: login

// Subclass can narrow the constructor to accept derived types
class ReadonlyEvent extends Event {
  // No new properties — just restricts to a subset of usage
  format(): string { return `[READ-ONLY] ${super.format()}`; }
}

abstract class Renderer {
  abstract render(element: string): string;
  wrap(element: string): string { return `[${this.render(element)}]`; }
}

class HtmlRenderer extends Renderer {
  override render(element: string): string {
    return `<${element}></${element}>`;
  }
}

class MarkdownRenderer extends Renderer {
  override render(element: string): string {
    return `# ${element}`;
  }
}

class PlaintextRenderer extends Renderer {
  override render(element: string): string {
    return element.toUpperCase();
  }
}

// Polymorphic function — works with any Renderer subclass
function renderAll(renderer: Renderer, elements: string[]): string[] {
  return elements.map(e => renderer.render(e));
}

const html = new HtmlRenderer();
const md   = new MarkdownRenderer();

console.log(renderAll(html, ['h1', 'p']));    // ['<h1></h1>', '<p></p>']
console.log(renderAll(md,   ['Title', 'Sub'])); // ['# Title', '# Sub']

// Array of base type — holds any mix of subclasses
const renderers: Renderer[] = [html, md, new PlaintextRenderer()];
renderers.forEach(r => console.log(r.wrap('div')));

// Inappropriate inheritance — Dog is not a Stack
// class DogList extends Stack<Dog> {} // wrong — misleading IS-A relationship

// Prefer composition
class DogList {
  private readonly store: Stack<Dog>;

  constructor() { this.store = new Stack<Dog>(); }

  addDog(dog: Dog): void { this.store.push(dog); }
  getLatest(): Dog | undefined { return this.store.pop(); }
}

// Rule of thumb: inheritance is appropriate when
// 1. The subclass passes the Liskov Substitution Principle (LSP):
//    anywhere the base type is expected, the subclass works correctly.
// 2. The subclass shares a substantial amount of the base implementation.
// 3. You need polymorphic dispatch (base-typed collections, abstract methods).

// Use composition (has-a) instead of inheritance (is-a) when:
// - You only want one or two methods
// - The subclass would violate LSP
// - The base class is not designed for inheritance (no protected/abstract members)

class Stack<T> {
  private items: T[] = [];
  push(item: T): void { this.items.push(item); }
  pop(): T | undefined { return this.items.pop(); }
  get size(): number { return this.items.length; }
}

