import { Component, Directive, HostListener } from '@angular/core';

// Base directive — not decorated with @Component, so it is reusable via inheritance
class BaseFormHandler {
  protected isDirty = false;
  protected isSubmitting = false;

  protected markDirty(): void { this.isDirty = true; }

  protected async submit(action: () => Promise<void>): Promise<void> {
    if (this.isSubmitting) return;
    this.isSubmitting = true;
    try { await action(); }
    finally { this.isSubmitting = false; }
  }
}

// @Component is placed on the SUBCLASS — it does NOT inherit from the base decorator
@Component({
  selector: 'app-login-form',
  template: `
    <button [disabled]="isSubmitting" (click)="handleSubmit()">
      {{ isSubmitting ? 'Logging in…' : 'Log in' }}
    </button>
  `,
})
class LoginFormComponent extends BaseFormHandler {
  async handleSubmit(): Promise<void> {
    this.markDirty();
    await this.submit(async () => {
      // call auth API
    });
  }
}

@Component({
  selector: 'app-register-form',
  template: `<button [disabled]="isSubmitting" (click)="handleSubmit()">Register</button>`,
})
class RegisterFormComponent extends BaseFormHandler {
  async handleSubmit(): Promise<void> {
    await this.submit(async () => {
      // call register API
    });
  }
}
// Both components share the form-handling logic — decorator metadata stays per-class
